function usd(v){return v==null||isNaN(v)?'Dato no informado':'USD '+Math.round(v).toLocaleString('es-AR')}
function fixed(v,d=1){return v==null||isNaN(v)?'Dato no informado':Number(v).toLocaleString('es-AR',{minimumFractionDigits:d,maximumFractionDigits:d})}
function label(k){return labels[k][state[k]]||state[k]}

function floorNum(u){let n=parseFloat(String(u.floor).replace(',','.'));return isNaN(n)?0:n}
function isDuplex(u){return String(u.typology||'').toLowerCase().includes('duplex')||String(u.typology||'').toLowerCase().includes('dúplex')}
function isLocal(u){return u.commercial||String(u.typology||'').toLowerCase().includes('local')}
function normN(u){let n=String(u.neighborhood||''); if(n.includes('Palermo'))return 'Palermo Hollywood'; if(n.includes('Núñez'))return 'Núñez'; if(n.includes('Cole'))return 'Colegiales'; if(n.includes('Devoto'))return 'Villa Devoto'; if(n.includes('Boedo'))return 'Boedo'; if(n.includes('Chacabuco'))return 'Parque Chacabuco'; if(n.includes('Canning'))return 'Canning'; return n}
function zoneOk(u){let n=normN(u); if(state.zone==='all')return true; if(state.zone==='north')return ['Palermo Hollywood','Núñez','Colegiales','Villa Devoto'].includes(n); return u.universo==='CABA'}
function productOk(u){if(state.product==='mixed')return !u.parkingOnly; if(state.product==='bulk')return !u.parkingOnly; return !isLocal(u)&&!u.parkingOnly}

function maxDown(p=state){return downMax[p.down]} function maxMonth(p=state){return monthMax[p.monthly]} function sal(p=state){return salarioMid[p.salary]}
function capacityLevel(p=state){let pts=0; if(p.salary==='top')pts+=4; else if(p.salary==='high')pts+=3; else if(p.salary==='mid')pts+=1; if(p.down==='dplus')pts+=4; else if(p.down==='d250')pts+=4; else if(p.down==='d120')pts+=3; else if(p.down==='d55')pts+=1; if(p.monthly==='mplus')pts+=4; else if(p.monthly==='m4500')pts+=3; else if(p.monthly==='m2500')pts+=1; if(p.product==='bulk'||p.priority==='pbulk')pts+=2; if(p.objective==='patrimony'||p.priority==='pmeters'||p.priority==='pcost')pts+=1; if(pts>=11)return 'max'; if(pts>=8)return 'very_high'; if(pts>=5)return 'high'; if(pts>=3)return 'mid'; return 'entry'}
function isMaxPower(p=state){return p.salary==='top'&&(p.down==='dplus'||p.down==='d250')&&p.monthly==='mplus'}
function isPackEligible(p=state){return p.priority!=='plocal'}
function wantsPack(p=state){return p.product==='bulk'||p.priority==='pbulk'}
function quietPackAllowed(p=state){return isPackEligible(p)&&['high','very_high','max'].includes(capacityLevel(p))}
function isHighProfile(p=state){return ['high','top'].includes(p.salary)||['d120','d250','dplus'].includes(p.down)||['m4500','mplus'].includes(p.monthly)||['patrimony'].includes(p.objective)||['pmeters','pcost','pbulk','plocal'].includes(p.priority)||p.product==='bulk'}
function candidateUnits(p=state, tolerance=.18){return units.filter(u=>zoneOk(u)&&productOk(u)&&u.financed&&u.down&&u.monthly).filter(u=>{let commercial=isLocal(u); let level=capacityLevel(p); let downTol=commercial?Math.max(tolerance,.25):tolerance; let monthTol=commercial?Math.max(tolerance,.25):tolerance; let priceFactor=(p.salary==='top'?99:(commercial?2.2:1.7)); if(level==='max')return true; return u.down<=maxDown(p)*(1+downTol)&&u.monthly<=maxMonth(p)*(1+monthTol)&&u.financed<=salaryCeiling[p.salary]*priceFactor})}
function locationScore(u,p){let n=normN(u); let map={'Palermo Hollywood':35,'Núñez':32,'Colegiales':28,'Villa Devoto':22,'Boedo':18,'Parque Chacabuco':17,'Canning':10}; let s=map[n]||14; if(p.objective==='rent'||p.objective==='resale'){if(['Palermo Hollywood','Núñez','Colegiales'].includes(n))s+=15} if(p.objective==='return'){if(['Núñez','Colegiales','Villa Devoto','Palermo Hollywood'].includes(n))s+=10} if(n==='Canning'&&(p.zone==='all'||p.zone==='caba_plus'||isMaxPower(p))&&(p.objective==='patrimony'||p.priority==='pmeters'||p.priority==='pcost'||p.priority==='pbulk'||p.product==='bulk'||capacityLevel(p)==='max'))s+=18; return s}
function affordabilityScore(u,p,reasons){let s=0; let impact=u.monthly/sal(p)*100; if(u.down<=maxDown(p)){s+=24; reasons.push('anticipo dentro del rango declarado')} else {s-=22; reasons.push('anticipo por encima del rango declarado')} if(u.monthly<=maxMonth(p)){s+=24; reasons.push('cuota dentro del rango declarado')} else {s-=22; reasons.push('cuota por encima del rango declarado')} if(impact<=14){s+=12; reasons.push('impacto mensual bajo: '+impact.toFixed(1)+'% del salario')} else if(impact<=24){s+=8; reasons.push('impacto mensual razonable: '+impact.toFixed(1)+'% del salario')} else {s-=8; reasons.push('impacto mensual alto: '+impact.toFixed(1)+'% del salario')} return s}
function priceM2Score(u,cands,reasons){let vals=cands.map(x=>x.psmFin).filter(Boolean).sort((a,b)=>a-b); if(!u.psmFin||!vals.length)return 0; let rank=vals.findIndex(x=>x>=u.psmFin)/(vals.length-1||1); if(rank<.25){reasons.push('precio/m² competitivo dentro del set compatible');return 18} if(rank<.5)return 9; if(rank>.85)return -6; return 2}
function targetBand(p){let level=capacityLevel(p); if(level==='max')return {min:250000,ideal:550000,softMin:180000}; if(level==='very_high')return {min:190000,ideal:380000,softMin:150000}; if(level==='high')return {min:135000,ideal:260000,softMin:110000}; if(level==='mid')return {min:85000,ideal:170000,softMin:70000}; return {min:0,ideal:125000,softMin:0}}
function ticketFitScore(u,p,reasons){let s=0; let level=capacityLevel(p); let band=targetBand(p); let downUse=u.down/maxDown(p); let monthUse=u.monthly/maxMonth(p); if(['max','very_high','high'].includes(level)){ if(u.financed>=band.min){s+=34; reasons.push('ticket proporcional a la capacidad declarada')} else if(u.financed>=band.softMin){s+=10; reasons.push('ticket conservador pero compatible con la capacidad declarada')} else {s-=42; reasons.push('ticket demasiado bajo para los números cargados')} if(isLocal(u)&&['max','very_high'].includes(level))s+=16; if(isDuplex(u)||Number(u.rooms)>=3||u.financed>=band.ideal*0.65)s+=14; if(downUse>.18&&downUse<1.05)s+=8; if(monthUse>.12&&monthUse<1.05)s+=8; } else { if(u.financed<=150000)s+=15; if(downUse<.85)s+=8; if(monthUse<.85)s+=8; if(u.financed>180000)s-=12; } return s}
function typologyScore(u,p,reasons){let s=0; let rooms=Number(u.rooms||0); if(p.objective==='start'){if(['high','very_high','max'].includes(capacityLevel(p))){if(rooms>=2||isLocal(u)){s+=14;reasons.push('aunque sea principiante, sus números permiten un producto de mayor escala')}} else if(rooms<=2){s+=18;reasons.push('tipología simple para primer inversor')}} if(p.objective==='rent'){if(rooms>0&&rooms<=2)s+=18;} if(p.objective==='resale'){if(rooms>=1&&rooms<=2)s+=14; if(String(u.layout).toLowerCase().includes('frente'))s+=8; if(floorNum(u)>=3)s+=5;} if(p.objective==='return'){if(rooms>=2)s+=16; if((u.total||0)>=50)s+=8;} if(p.objective==='patrimony'){if(rooms>=3)s+=16; if(isDuplex(u))s+=22; if((u.total||0)>=90)s+=14;} if(['max','very_high'].includes(capacityLevel(p))&&rooms>=3){s+=12;reasons.push('producto de mayor escala acorde al perfil')} return s}
function priorityScore(u,p,reasons){let s=0; let n=normN(u); if(p.priority==='fit')s+=ticketFitScore(u,p,reasons); if(p.priority==='pdown'){s+=Math.max(0,24-u.down/3500); reasons.push('prioriza menor anticipo')} if(p.priority==='pmonthly'){s+=Math.max(0,24-u.monthly/180); reasons.push('prioriza menor cuota mensual')} if(p.priority==='plocation'){s+=locationScore(u,p)*.75; reasons.push('prioriza ubicación')} if(p.priority==='presale'){if(['Palermo Hollywood','Núñez','Colegiales'].includes(n))s+=22; if(String(u.layout).toLowerCase().includes('frente'))s+=8; reasons.push('prioriza reventa futura')} if(p.priority==='prent'){if(['Palermo Hollywood','Colegiales','Núñez'].includes(n))s+=20; if(Number(u.rooms)<=2)s+=12; reasons.push('prioriza renta futura')} if(p.priority==='pmeters'){s+=Math.min(30,(u.total||0)/5); reasons.push('prioriza metros y usabilidad')} if(p.priority==='pcost'){if(String(u.developer).includes('Emprendeprop'))s+=18; if(Number(u.installments)>=60)s+=10; reasons.push('prioriza largo plazo / forma de pago')} if(p.priority==='plocal'){if(isLocal(u)){s+=42; reasons.push('prioriza producto comercial')} else {s-=18}} if(p.priority==='pbulk'){if(!isLocal(u))s+=12; else s+=18; reasons.push('habilita pack mayorista o producto comercial si los números dan')} return s}
function scoreUnit(u,p,cands){let reasons=[]; let s=0; if(isLocal(u)){s+=18; reasons.push('local comercial disponible con precio, anticipo y cuota cargados'); if(p.priority==='plocal'){s+=44; reasons.push('perfil habilitó locales comerciales')} if(['top','high'].includes(p.salary)||p.down==='dplus'||p.monthly==='mplus'){s+=18; reasons.push('ticket comercial compatible con mayor capacidad declarada')} } s+=affordabilityScore(u,p,reasons); s+=locationScore(u,p); s+=priceM2Score(u,cands,reasons); s+=ticketFitScore(u,p,reasons); s+=typologyScore(u,p,reasons); s+=priorityScore(u,p,reasons); if(String(u.layout).toLowerCase().includes('frente'))s+=5; if(floorNum(u)>=5)s+=4; if((u.semi||0)+(u.uncovered||0)>25){s+=7; reasons.push('metros exteriores diferenciales')} if(u.cash&&u.psmCash&&u.psmFin&&u.psmCash/u.psmFin<.82){s+=8; reasons.push('contado competitivo frente al financiado')} return Object.assign({},u,{score:s,reasons:[...new Set(reasons)].slice(0,6),impact:u.monthly/sal(p)*100,type:'unit'})}
function buildPack(p,picked,size,label,scoreBonus=0,packMode='normal'){
 let sum=(k)=>picked.reduce((a,x)=>a+(Number(x[k])||0),0);
 let total=sum('total');
 let allCash=picked.every(x=>x.cash);
 let pack={type:'pack',id:label.replace(/\s+/g,'-')+'-'+size+'-'+picked.map(x=>x.id).join('-'),packSize:size,units:picked,building:label,unit:picked.map(x=>x.building+' UF '+x.unit).join(' + '),neighborhood:label.includes('Aura')?'Canning':'Cartera combinada',typology:(packMode==='aggressive'?'Pack agresivo de ':'Pack de ')+size+' departamentos',financed:sum('financed'),down:sum('down'),monthly:sum('monthly'),cash:allCash?sum('cash'):null,total:total,covered:sum('covered'),semi:sum('semi'),uncovered:sum('uncovered'),psmFin:total?sum('financed')/total:null,psmCash:(allCash&&total)?sum('cash')/total:null,payment:'Pack sujeto a negociación',developer:label.includes('Aura')?'Moderna Construcciones S.A.':'Cartera combinada',address:label.includes('Aura')?'Complejo Aura Canning':'Varias direcciones',floor:'Varios',layout:'Mixto',orientation:'Dato no informado',delivery:label.includes('Aura')?'Primer edificio estimado noviembre 2029; edificios 3 y 4 a confirmar':'Según cada unidad',missing:'Confirmar disponibilidad simultánea, condiciones mayoristas y aprobación de descuento por desarrolladora.',conditions:'Compra mayorista: puede abrir conversación por condiciones especiales/descuentos, sujeto a aprobación y disponibilidad real.',score:0,reasons:[],packMode:packMode};
 let slack=isMaxPower(p)?2.5:(wantsPack(p)?1.25:1.05);
 let afford=(pack.down<=maxDown(p)*slack&&pack.monthly<=maxMonth(p)*slack);
 if(!afford)return null;
 let level=capacityLevel(p);
 let baseScore=(level==='max'?240:(level==='very_high'?205:(level==='high'?175:125)));
 pack.score=baseScore+scoreBonus+(size===5?35:0)+(p.priority==='pbulk'?45:0)+(p.product==='bulk'?35:0)+(packMode==='aggressive'?30:0)+(label.includes('Aura')?18:0); if(level==='max'&&packMode==='aggressive')pack.score+=Math.min(140,pack.financed/10000);
 pack.reasons=label.includes('Aura')?
 ['pack Aura Canning de '+size+' unidades compatible con tus números','Aura tiene volumen disponible y permite pensar compra por cantidad','30% + 60 cuotas: estructura útil para estrategia patrimonial/largo plazo','compra mayorista: puede abrir conversación por condiciones/descuento sujetas a aprobación']:
 [packMode==='aggressive'?'pack agresivo de '+size+' unidades acorde a capacidad máxima':'pack de '+size+' unidades dentro de los números declarados','permite diversificar ticket en varias unidades','compra mayorista: puede habilitar negociación de condiciones/descuento','ideal para estrategia patrimonial o compra por volumen'];
 return pack;
}
function packCandidates(p,cands){
 if(!quietPackAllowed(p))return [];
 let level=capacityLevel(p);
 let maxed=isMaxPower(p);
 let useAll=maxed||wantsPack(p);
 let poolSource=useAll?units.filter(u=>zoneOk(u)&&!isLocal(u)&&!u.parkingOnly&&u.financed&&u.down&&u.monthly):cands.filter(u=>!isLocal(u)&&!u.parkingOnly&&u.financed&&u.down&&u.monthly);
 let scoreForConservative=(u)=>{let n=normN(u); return (['Palermo Hollywood','Núñez','Colegiales'].includes(n)?34:0)+(n==='Canning'?20:0)+(u.financed<150000?18:0)+(u.psmFin?Math.max(0,3000-u.psmFin)/38:0)+(String(u.layout).toLowerCase().includes('frente')?5:0)+(u.rooms<=2?8:0)};
 let scoreForAggressive=(u)=>{let n=normN(u); return (['Palermo Hollywood','Núñez','Colegiales'].includes(n)?32:0)+(isDuplex(u)?35:0)+(u.rooms>=3?28:0)+(u.financed>180000?24:0)+(u.total>90?20:0)+(String(u.layout).toLowerCase().includes('frente')?8:0)+(floorNum(u)>=4?6:0)};
 let baseScored=poolSource.map(u=>scoreUnit(u,p,poolSource));
 let packs=[];
 // Pack tranquilo: varias unidades líquidas y más fáciles de revender.
 for(let size of [3]){
   let picked=[]; let usedBuildings=new Map();
   for(let u of [...baseScored].sort((a,b)=>scoreForConservative(b)-scoreForConservative(a))){
     if(picked.some(x=>x.id===u.id))continue; let count=usedBuildings.get(u.building)||0; if(count>=2)continue; picked.push(u); usedBuildings.set(u.building,count+1); if(picked.length===size)break;
   }
   if(picked.length===size){let pack=buildPack(p,picked,size,'Pack tranquilo '+size+' unidades',18,'tranquilo'); if(pack)packs.push(pack)}
 }
 // Pack agresivo: se activa fuerte si el perfil maxea capacidad o pide mayorista.
 if(maxed||wantsPack(p)||level==='very_high'){
   for(let size of [5,3]){
     let picked=[];
     for(let u of [...baseScored].sort((a,b)=>scoreForAggressive(b)-scoreForAggressive(a))){if(!picked.some(x=>x.id===u.id)){picked.push(u)} if(picked.length===size)break;}
     if(picked.length===size){let pack=buildPack(p,picked,size,'Pack mayorista agresivo '+size+' unidades',45,'aggressive'); if(pack)packs.push(pack)}
   }
 }
 // Pack Aura: aparece si el usuario abre Canning, pide packs/largo plazo o maxea toda la capacidad.
 let allowAuraPack=(p.priority!=='plocal'&&(p.zone==='all'||p.zone==='caba_plus'||p.product==='bulk'||p.priority==='pbulk'||p.priority==='pcost'||maxed));
 if(allowAuraPack){
   let auraPool=units.filter(u=>u.building==='Aura Canning'&&!isLocal(u)&&!u.parkingOnly&&u.financed&&u.down&&u.monthly).map(u=>scoreUnit(u,p,units.filter(x=>x.building==='Aura Canning'))).sort((a,b)=>{let sa=(a.financed<95000?28:0)+(a.financed<120000?12:0)+(String(a.layout).toLowerCase().includes('frente')?8:0)+(a.psmFin?Math.max(0,1900-a.psmFin)/18:0)+(a.rooms<=2?8:0); let sb=(b.financed<95000?28:0)+(b.financed<120000?12:0)+(String(b.layout).toLowerCase().includes('frente')?8:0)+(b.psmFin?Math.max(0,1900-b.psmFin)/18:0)+(b.rooms<=2?8:0); return sb-sa;});
   for(let size of [5,3]){let picked=[]; for(let u of auraPool){if(!picked.some(x=>x.id===u.id)){picked.push(u)} if(picked.length===size)break;} if(picked.length===size){let pack=buildPack(p,picked,size,'Pack Aura Canning '+size+' unidades',55,'aggressive'); if(pack)packs.push(pack)}}
 }
 let seen=new Set();
 return packs.filter(pck=>{let key=pck.units.map(u=>u.id).sort().join('|'); if(seen.has(key))return false; seen.add(key); return true}).sort((a,b)=>b.score-a.score);
}

function profileName(p){if(p.priority==='plocal')return 'inversor comercial'; if(p.product==='bulk'||p.priority==='pbulk')return 'inversor mayorista / cartera'; if(capacityLevel(p)==='max')return 'inversor patrimonial con capacidad máxima'; if(isHighProfile(p))return 'inversor patrimonial / mayor capacidad de compra'; if(p.objective==='return')return 'comprador futuro / regreso a Argentina'; if(p.objective==='rent')return 'cliente que busca renta futura'; if(p.objective==='resale')return 'cliente que busca reventa futura'; if(p.salary==='low'&&p.down==='d55')return 'joven inversor de bajo capital'; return 'inversor racional en formación'}
function roleName(u,p){if(u.type==='pack')return u.packMode==='aggressive'?'Pack mayorista agresivo':'Pack mayorista / cartera'; if(isLocal(u))return 'Local comercial / inversión comercial'; if(capacityLevel(p)==='max')return 'Opción patrimonial acorde a capacidad máxima'; if(isHighProfile(p))return 'Opción acorde a tus números'; if(p.priority==='pdown')return 'Opción bajo anticipo'; if(p.priority==='pmonthly')return 'Opción bajo impacto mensual'; if(p.objective==='resale')return 'Opción liquidez / reventa'; if(p.objective==='rent')return 'Opción renta futura'; return 'Opción compatible con tus números'}
function recommend(p){let cands=candidateUnits(p,.15); if(!cands.length)cands=candidateUnits(p,.35); if(!cands.length)cands=units.filter(u=>zoneOk(u)&&productOk(u)); let ranked=cands.map(u=>scoreUnit(u,p,cands)).sort((a,b)=>b.score-a.score); let packs=(p.priority==='plocal')?[]:packCandidates(p,cands); let selected=[]; let maxed=isMaxPower(p); let packFirst=maxed||wantsPack(p); if(packFirst){for(let pack of packs){if(selected.length>=3)break; selected.push(pack)}} else if(quietPackAllowed(p)&&packs.length){selected.push(packs[0])} for(let item of [...packs,...ranked].sort((a,b)=>b.score-a.score)){ if(selected.length>=5)break; if(item.type==='pack'){if(!selected.some(x=>x.id===item.id)&&(packFirst||quietPackAllowed(p)))selected.push(item); continue} if(selected.some(x=>x.type==='unit'&&x.id===item.id))continue; selected.push(item)} return selected.map(x=>Object.assign(x,{roleName:roleName(x,p)})).slice(0,5)}
function unitLine(u){return `${u.building} UF ${u.unit} (${u.neighborhood}, ${u.typology}, ${usd(u.financed)}, anticipo ${usd(u.down)}, cuota ${usd(u.monthly)}/mes)`}
function whatsappMessage(u,profile){ if(isLocal(u)){return `Hola Juan, completé el recomendador y quiero consultar por este local comercial: ${u.building} - ${u.unit} - ${u.neighborhood} - ${usd(u.financed)}. Anticipo: ${usd(u.down)}. Cuota: ${usd(u.monthly)}/mes. Contado: ${usd(u.cash)}. Perfil detectado: ${profile}. ¿Me pasás información sobre disponibilidad, condiciones comerciales, posibilidad de descuento y destino/habilitación del local?`; } if(u.type==='pack'){let detail=u.units.map(unitLine).join(' | '); return `Hola Juan, completé el recomendador y quiero consultar por un pack mayorista de ${u.packSize} unidades. Total financiado aprox: ${usd(u.financed)}. Anticipo total: ${usd(u.down)}. Cuota total: ${usd(u.monthly)}/mes. Unidades: ${detail}. Perfil detectado: ${profile}. Entiendo que la compra mayorista puede incluir descuentos o condiciones especiales sujetas a aprobación y disponibilidad. ¿Me pasás más información?`; } return `Hola Juan, completé el recomendador y quiero consultar por esta unidad en particular: ${u.building} - Unidad ${u.unit} - ${u.neighborhood} - ${u.typology} - ${usd(u.financed)}. Anticipo: ${usd(u.down)}. Cuota: ${usd(u.monthly)}/mes. Perfil detectado: ${profile}. ¿Me pasás más información?`; }


function optionSubtitle(q, value){
  const found = q.options.find(o => o[0] === value);
  return found ? `${found[1]} · ${found[2]}` : '';
}
function renderPanels(){
  const q = questions[openIndex];
  const progress = ((openIndex + 1) / questions.length) * 100;
  document.getElementById('stepCounter').textContent = `Paso ${openIndex + 1}`;
  document.getElementById('stepTotal').textContent = `de ${questions.length}`;
  document.getElementById('progressFill').style.width = `${progress}%`;
  document.getElementById('backBtn').disabled = openIndex === 0;
  document.getElementById('nextBtn').textContent = openIndex === questions.length - 1 ? 'Ver opciones' : 'Continuar';
  const reviewCompact = document.getElementById('reviewCompact');
  if(reviewCompact) reviewCompact.textContent = optionSubtitle(q, state[q.key]);
  document.getElementById('panels').innerHTML = `
    <article class="step-card" data-step="${q.key}">
      <div class="selection-pill"><i></i>${optionSubtitle(q, state[q.key])}</div>
      <div class="step-kicker">${String(q.key).replace('_',' ')}</div>
      <h2 class="step-title">${q.title}</h2>
      <p class="step-hint">${q.hint}</p>
      <div class="options">
        ${q.options.map(o => `
          <button class="option-card ${state[q.key] === o[0] ? 'selected' : ''}" type="button" onclick="selectOption('${q.key}','${o[0]}',${openIndex})">
            <span class="option-dot"></span>
            <span class="option-text"><strong>${o[1]}</strong><span>${o[2]}</span></span>
          </button>
        `).join('')}
      </div>
    </article>`;
  renderReview();
}
function renderReview(){
  const list=document.getElementById('reviewList');
  if(!list)return;
  list.innerHTML=questions.map((q,idx)=>`<button class="review-row ${idx===openIndex?'active':''}" type="button" onclick="jumpTo(${idx})"><span><small>${q.title}</small><b>${optionSubtitle(q,state[q.key])}</b></span><em>Editar</em></button>`).join('');
}
function jumpTo(idx){
  openIndex=Math.max(0,Math.min(idx,questions.length-1));
  renderPanels();
  document.getElementById('wizard').scrollIntoView({behavior:'smooth',block:'start'});
}
function selectOption(k,v,i){
  state[k] = v;
  renderPanels();
  if(i < questions.length - 1){
    setTimeout(()=>{ openIndex = i + 1; renderPanels(); }, 180);
  } else {
    setTimeout(()=>{ calculate(); }, 180);
  }
}
function nextStep(){
  if(openIndex >= questions.length - 1){ calculate(); return; }
  openIndex = Math.min(openIndex + 1, questions.length - 1);
  renderPanels();
}
function backStep(){
  openIndex = Math.max(openIndex - 1, 0);
  renderPanels();
}
function renderMetric(label,value){return `<div class="metric"><small>${label}</small><b>${value}</b></div>`}
function renderCard(u,i,profile){
  let msg=encodeURIComponent(whatsappMessage(u,profile));
  let isPack=u.type==='pack';
  let isLocalCard=isLocal(u);
  let cardClass=isPack?'pack':(isLocalCard?'local':'unit');
  let tags=isPack?['Pack mayorista',u.packSize+' unidades','Condiciones a negociar']:(isLocalCard?['Local comercial','Consulta condiciones','Producto comercial']:[u.segment,u.payment,normN(u),u.developer.includes('Emprendeprop')?'Club Conecta':'Moderna'].filter(Boolean).slice(0,4));
  let m2ext=(Number(u.semi||0)+Number(u.uncovered||0));
  let title=isPack?u.building:`${u.building} · Unidad ${u.unit}`;
  let subtitle=isPack?`${u.packSize} unidades · ${usd(u.financed)} · ${usd(u.monthly)}/mes`:`${u.neighborhood} · ${u.typology} · ${usd(u.monthly)}/mes`;
  let included=isPack?`<div class="why"><b>Unidades incluidas</b>${u.units.map(unitLine).join('<br>')}</div>`:'';
  return `<details class="result-card ${cardClass}" ${i===0?'open':''}>
    <summary>
      <div class="result-index">${i+1}</div>
      <div class="result-main">
        <div class="result-title">${title}</div>
        <div class="result-sub">${subtitle}</div>
        <span class="role-badge">${u.roleName}</span>
      </div>
      <div class="chevron">+</div>
    </summary>
    <div class="result-body">
      <div class="mini-address">${u.address || 'Dirección a confirmar'}<br>Piso ${u.floor || 'Dato no informado'} · ${u.layout || 'Dato no informado'} · orientación: ${u.orientation || 'Dato no informado'} · entrega: ${u.delivery || 'Dato no informado'}</div>
      <div class="metrics">
        ${renderMetric('Precio financiado',usd(u.financed))}
        ${renderMetric('Anticipo',usd(u.down))}
        ${renderMetric('Cuota',usd(u.monthly)+'/mes')}
        ${renderMetric('m² totales',fixed(u.total,1)+' m²')}
        ${renderMetric('Contado',usd(u.cash))}
        ${renderMetric('Precio/m² financiado',usd(u.psmFin))}
        ${renderMetric('m² cubiertos',u.covered?fixed(u.covered,1)+' m²':'Dato no informado')}
        ${renderMetric('m² exteriores',m2ext?fixed(m2ext,1)+' m²':'Dato no informado')}
      </div>
      <div class="why"><b>Por qué aparece</b>${(u.reasons||[]).join('; ')}</div>
      ${included}
      <div class="tags">${tags.map(t=>`<span class="tag">${t}</span>`).join('')}</div>
      <div class="alert-box"><b>Datos a confirmar</b>${u.missing || 'Disponibilidad real actual y condiciones finales.'}</div>
      <a class="wa" href="https://wa.me/${PHONE}?text=${msg}" target="_blank" rel="noopener">Consultar por WhatsApp</a>
    </div>
  </details>`;
}
function calculate(){
  let p={...state};
  let profile=profileName(p);
  document.body.classList.add('is-complete');
  document.getElementById('wizard').style.display='none';
  document.getElementById('results').style.display='none';
  document.getElementById('loading').style.display='grid';
  setTimeout(()=>{
    let rec=recommend(p);
    document.getElementById('summary').innerHTML=`Perfil detectado: <b>${profile}</b>. Se priorizaron opciones compatibles con <b>${label('down')}</b> de anticipo y <b>${label('monthly')}</b> de cuota. La experiencia no baja el ticket por sí sola: el sistema se guía por ingresos, anticipo y cuota. Si tus números lo permiten, puede elevar ticket, incluir packs o sumar locales sin presentar una escalera fija de barato/intermedio/caro.`;
    document.getElementById('cards').innerHTML=rec.map((u,i)=>renderCard(u,i,profile)).join('');
    document.getElementById('loading').style.display='none';
    document.getElementById('results').style.display='block';
    setTimeout(()=>document.getElementById('results').scrollIntoView({behavior:'smooth',block:'start'}),80);
  }, 650);
}
function resetAll(){
  state={age:'initial',salary:'low',experience:'zero',objective:'start',zone:'caba',product:'residential',down:'d55',monthly:'m1500',priority:'fit'};
  openIndex=0;
  document.body.classList.remove('is-complete');
  document.getElementById('wizard').style.display='block';
  document.getElementById('results').style.display='none';
  document.getElementById('loading').style.display='none';
  renderPanels();
  window.scrollTo({top:0,behavior:'smooth'});
}
function initApp(){
  document.getElementById('countUnits').textContent=APP_DATA.metadata.total_unidades_disponibles_cargadas||units.length;
  document.getElementById('countCaba').textContent=units.filter(u=>u.universo==='CABA').length;
  document.getElementById('countProjects').textContent=[...new Set(units.map(u=>u.building))].length;
  renderPanels();
  if('serviceWorker' in navigator){navigator.serviceWorker.register('service-worker.js').catch(()=>{})}
}
initApp();
